"""Feedback and agent-observation tools."""

from __future__ import annotations

from datetime import UTC, datetime
from typing import Any

from agent_kit.tool_kit import ToolContext, register_tool


JSONDict = dict[str, Any]

USER_FEEDBACK_KINDS = {"style", "process", "epic_specific"}
OBSERVATION_KINDS = {
    "friction",
    "ambiguity",
    "tool_failure",
    "confusion",
    "pattern_noticed",
}
USER_FEEDBACK_SOURCES = {
    "user_volunteered",
    "agent_proposed_user_confirmed",
    "explicit_save_request",
}
OBSERVATION_SOURCE = "agent_observation"

SAVE_FEEDBACK_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "required": ["kind", "content"],
    "properties": {
        "kind": {"type": "string"},
        "content": {"type": "string"},
        "source": {"type": "string"},
        "source_message_id": {"type": ["string", "null"]},
        "epic_id": {"type": ["string", "null"]},
        "context_snapshot": {"type": ["object", "null"]},
    },
}

FEEDBACK_ID_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "required": ["feedback_id"],
    "properties": {
        "feedback_id": {"type": "string"},
    },
}

DEACTIVATE_FEEDBACK_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "required": ["feedback_id", "reason"],
    "properties": {
        "feedback_id": {"type": "string"},
        "reason": {"type": "string"},
    },
}

LIST_FEEDBACK_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "properties": {
        "epic_id": {"type": ["string", "null"]},
        "active": {"type": ["boolean", "null"]},
        "kinds": {"type": ["array", "null"], "items": {"type": "string"}},
        "limit": {"type": ["integer", "null"]},
    },
}

RECORD_OBSERVATION_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "required": ["kind", "content"],
    "properties": {
        "kind": {"type": "string"},
        "content": {"type": "string"},
        "epic_id": {"type": ["string", "null"]},
        "bot_action_being_critiqued": {"type": ["string", "null"]},
        "context_snapshot": {"type": ["object", "null"]},
    },
}

LIST_OBSERVATIONS_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "properties": {
        "resolved": {"type": ["boolean", "null"]},
        "limit": {"type": ["integer", "null"]},
    },
}

MARK_OBSERVATION_RESOLVED_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "required": ["feedback_id", "resolution_note"],
    "properties": {
        "feedback_id": {"type": "string"},
        "resolution_note": {"type": "string"},
    },
}


@register_tool(
    "save_feedback",
    schema=SAVE_FEEDBACK_SCHEMA,
    operation_kind="write",
)
def save_feedback(
    context: ToolContext,
    kind: str,
    content: str,
    source: str = "explicit_save_request",
    source_message_id: str | None = None,
    epic_id: str | None = None,
    context_snapshot: JSONDict | None = None,
) -> JSONDict:
    if kind not in USER_FEEDBACK_KINDS:
        return {
            "error": "invalid_feedback_kind",
            "kind": kind,
            "allowed_kinds": sorted(USER_FEEDBACK_KINDS),
        }
    if source not in USER_FEEDBACK_SOURCES:
        return {
            "error": "invalid_feedback_source",
            "source": source,
            "allowed_sources": sorted(USER_FEEDBACK_SOURCES),
        }

    target_epic_id = epic_id
    if kind == "epic_specific" and target_epic_id is None:
        target_epic_id = _metadata_string(context, "epic_id")
    feedback = context.store.create_feedback(
        kind=kind,
        content=content,
        source=source,
        source_message_id=source_message_id or _metadata_string(context, "inbound_message_id"),
        epic_id=target_epic_id,
        turn_id=context.turn_id,
        context_snapshot=context_snapshot or _context_snapshot(context),
    )
    return {"feedback": feedback}


@register_tool(
    "apply_feedback",
    schema=FEEDBACK_ID_SCHEMA,
    operation_kind="write",
)
def apply_feedback(context: ToolContext, feedback_id: str) -> JSONDict:
    feedback = context.store.load_feedback(feedback_id)
    if not feedback:
        return {"error": "feedback_not_found", "feedback_id": feedback_id}
    if str(feedback.get("kind")) not in USER_FEEDBACK_KINDS:
        return {"error": "invalid_feedback_kind", "feedback_id": feedback_id}
    now = _now()
    updated = context.store.update_feedback(
        feedback_id,
        last_applied_at=now,
        last_referenced_at=now,
    )
    return {"feedback": updated}


@register_tool(
    "deactivate_feedback",
    schema=DEACTIVATE_FEEDBACK_SCHEMA,
    operation_kind="write",
)
def deactivate_feedback(
    context: ToolContext,
    feedback_id: str,
    reason: str,
) -> JSONDict:
    feedback = context.store.load_feedback(feedback_id)
    if not feedback:
        return {"error": "feedback_not_found", "feedback_id": feedback_id}
    if str(feedback.get("kind")) not in USER_FEEDBACK_KINDS:
        return {"error": "invalid_feedback_kind", "feedback_id": feedback_id}
    updated = context.store.update_feedback(
        feedback_id,
        active=False,
        deactivation_reason=reason,
        last_referenced_at=_now(),
    )
    return {"feedback": updated}


@register_tool(
    "list_feedback",
    schema=LIST_FEEDBACK_SCHEMA,
    operation_kind="write",
)
def list_feedback(
    context: ToolContext,
    epic_id: str | None = None,
    active: bool | None = True,
    kinds: list[str] | None = None,
    limit: int | None = None,
) -> JSONDict:
    invalid_kinds = sorted(set(kinds or []) - USER_FEEDBACK_KINDS)
    if invalid_kinds:
        return {
            "error": "invalid_feedback_kind",
            "kinds": invalid_kinds,
            "allowed_kinds": sorted(USER_FEEDBACK_KINDS),
        }
    rows = context.store.list_feedback(
        epic_id=epic_id,
        active=active,
        kinds=kinds,
        limit=limit,
    )
    referenced = _mark_referenced(context, rows)
    return {"feedback": referenced}


@register_tool(
    "record_observation",
    schema=RECORD_OBSERVATION_SCHEMA,
    operation_kind="write",
)
def record_observation(
    context: ToolContext,
    kind: str,
    content: str,
    epic_id: str | None = None,
    bot_action_being_critiqued: str | None = None,
    context_snapshot: JSONDict | None = None,
) -> JSONDict:
    if kind not in OBSERVATION_KINDS:
        return {
            "error": "invalid_observation_kind",
            "kind": kind,
            "allowed_kinds": sorted(OBSERVATION_KINDS),
        }
    observation = context.store.create_feedback(
        kind=kind,

        kind=kind,
        content=content,
        source=OBSERVATION_SOURCE,
        epic_id=epic_id or _metadata_string(context, "epic_id"),
        turn_id=context.turn_id,
        context_snapshot=context_snapshot
        or _context_snapshot(
            context,
            bot_action_being_critiqued=bot_action_being_critiqued,
        ),
    )
    return {"observation": observation}


@register_tool(
    "list_observations",
    schema=LIST_OBSERVATIONS_SCHEMA,
    operation_kind="write",
)
def list_observations(
    context: ToolContext,
    resolved: bool | None = False,
    limit: int | None = None,
) -> JSONDict:
    rows = context.store.list_observations(resolved=resolved, limit=limit)
    referenced = _mark_referenced(context, rows)
    return {"observations": referenced}


@register_tool(
    "mark_observation_resolved",
    schema=MARK_OBSERVATION_RESOLVED_SCHEMA,
    operation_kind="write",
)
def mark_observation_resolved(
    context: ToolContext,
    feedback_id: str,
    resolution_note: str,
) -> JSONDict:
    observation = context.store.load_feedback(feedback_id)
    if not observation:
        return {"error": "observation_not_found", "feedback_id": feedback_id}
    if str(observation.get("kind")) not in OBSERVATION_KINDS:
        return {"error": "invalid_observation_kind", "feedback_id": feedback_id}
    now = _now()
    updated = context.store.update_feedback(
        feedback_id,
        resolved=True,
        resolution_note=resolution_note,
        resolved_at=now,
        last_referenced_at=now,
    )
    return {"observation": updated}


def _mark_referenced(context: ToolContext, rows: list[JSONDict]) -> list[JSONDict]:
    if not rows:
        return []
    now = _now()
    return [
        context.store.update_feedback(str(row["id"]), last_referenced_at=now)
        for row in rows
    ]


def _context_snapshot(
    context: ToolContext,
    *,
    bot_action_being_critiqued: str | None = None,
) -> JSONDict:
    return {
        "user_message": context.metadata.get("user_message"),
        "bot_action_being_critiqued": bot_action_being_critiqued,
    }


def _metadata_string(context: ToolContext, key: str) -> str | None:
    value = context.metadata.get(key)
    return value if isinstance(value, str) and value else None


def _now() -> str:
    return datetime.now(UTC).isoformat(timespec="milliseconds").replace(
        "+00:00",
        "Z",
    )


__all__ = [
    "OBSERVATION_KINDS",
    "OBSERVATION_SOURCE",
    "USER_FEEDBACK_KINDS",
    "USER_FEEDBACK_SOURCES",
    "apply_feedback",
    "deactivate_feedback",
    "list_feedback",
    "list_observations",
    "mark_observation_resolved",
    "record_observation",
    "save_feedback",
]

"""Markdown body parsing and section-level editing helpers."""

from __future__ import annotations

from dataclasses import dataclass, replace
import difflib
import re


HEADING_RE = re.compile(r"^##\s+(.+?)\s*$")
ANY_SECTION_HEADING_RE = re.compile(r"^(#{2,6})\s+(.+?)\s*$")
TITLE_RE = re.compile(r"^#\s+(.+?)\s*$")
_FENCE_RE = re.compile(r"^\s*(```|~~~)")
_PREAMBLE = "_preamble"


class BodyValidationError(ValueError):
    pass


class SectionNotFound(ValueError):
    pass


class SectionExists(ValueError):
    pass


class InvalidPosition(ValueError):
    pass


@dataclass(frozen=True)
class Section:
    name: str
    heading: str
    content: str

    @property
    def raw(self) -> str:
        return f"{self.heading}{self.content}"


@dataclass(frozen=True)
class ParsedBody:
    title: str | None
    goal_first_paragraph: str | None
    preamble: str
    sections: list[Section]


def parse(body: str) -> ParsedBody:
    """Parse markdown into title, preamble, and top-level ## sections.

    This function is deliberately lenient and never raises for malformed body
    text. Validation for writes is handled by ``validate_for_write``.
    """

    try:
        text = "" if body is None else str(body)
        boundaries = _section_boundaries(text)
        if not boundaries:
            preamble = text
            sections: list[Section] = []
        else:
            preamble = text[: boundaries[0][0]]
            sections = []
            for index, (start, end, name, heading) in enumerate(boundaries):
                next_start = boundaries[index + 1][0] if index + 1 < len(boundaries) else len(text)
                sections.append(Section(name=name, heading=heading, content=text[end:next_start]))
        return ParsedBody(
            title=_extract_title(preamble),
            goal_first_paragraph=_extract_goal(sections),
            preamble=preamble,
            sections=sections,
        )
    except Exception:
        return ParsedBody(title=None, goal_first_paragraph=None, preamble="" if body is None else str(body), sections=[])


def serialize(parsed: ParsedBody) -> str:
    return parsed.preamble + "".join(section.raw for section in parsed.sections)


def validate_for_write(parsed: ParsedBody) -> None:
    if not parsed.title:
        raise BodyValidationError("body_missing_required_section: title")
    if not parsed.goal_first_paragraph:
        raise BodyValidationError("body_missing_required_section: goal")


def outline(parsed: ParsedBody) -> dict[str, object]:
    body_text = serialize(parsed)
    section_spans = _section_line_spans(body_text)
    return {
        "title": parsed.title,
        "goal": parsed.goal_first_paragraph,
        "total_lines": _line_count(body_text),
        "sections": [
            {
                "name": section.name,
                "line_count": _line_count(section.raw),
                "line_start": span["line_start"],
                "line_end": span["line_end"],
                "subheadings": _nested_subheadings(
                    section_spans,
                    span["line_start"],
                    span["line_end"],
                ),
            }
            for section, span in zip(parsed.sections, section_spans)
        ],
    }


def search(parsed: ParsedBody, query: str, context_lines: int = 2) -> dict[str, object]:
    body_text = serialize(parsed)
    needle = str(query or "").casefold()
    context_size = max(int(context_lines), 0)
    lines = body_text.splitlines()
    section_spans = _section_line_spans(body_text)
    results: list[dict[str, object]] = []
    if not needle:
        return {"query": query, "results": []}

    for index, line in enumerate(lines):
        if needle not in line.casefold():
            continue
        line_number = index + 1
        start = max(0, index - context_size)
        end = min(len(lines), index + context_size + 1)
        results.append(
            {
                "line_number": line_number,
                "line": line,
                "section": _section_name_for_line(section_spans, line_number),
                "subheading_path": _subheading_path_for_line(section_spans, line_number),
                "context_before": [
                    {"line_number": item + 1, "line": lines[item]}
                    for item in range(start, index)
                ],
                "context_after": [
                    {"line_number": item + 1, "line": lines[item]}
                    for item in range(index + 1, end)
                ],
            }
        )
    return {"query": query, "results": results}


def replace_section(parsed: ParsedBody, name: str, content: str) -> ParsedBody:
    if name == _PREAMBLE:
        return parse(str(content) + "".join(section.raw for section in parsed.sections))
    index = _section_index(parsed, name)
    sections = list(parsed.sections)
    sections[index] = replace(sections[index], content=str(content))
    return parse(parsed.preamble + "".join(section.raw for section in sections))


def append_to_section(parsed: ParsedBody, name: str, content: str) -> ParsedBody:
    if name == _PREAMBLE:
        return replace_section(parsed, name, parsed.preamble + str(content))
    index = _section_index(parsed, name)
    sections = list(parsed.sections)
    sections[index] = replace(sections[index], content=sections[index].content + str(content))
    return parse(parsed.preamble + "".join(section.raw for section in sections))


def add_section(parsed: ParsedBody, name: str, content: str, position: str = "end") -> ParsedBody:
    if name == _PREAMBLE:
        raise SectionExists(_PREAMBLE)
    if any(section.name == name for section in parsed.sections):
        raise SectionExists(name)
    sections = list(parsed.sections)
    section = Section(name=name, heading=f"## {name}\n", content=str(content))
    index = _position_index(parsed, position)
    sections.insert(index, section)
    return parse(parsed.preamble + "".join(item.raw for item in sections))


def remove_section(parsed: ParsedBody, name: str) -> ParsedBody:
    if name == _PREAMBLE:
        return parse("".join(section.raw for section in parsed.sections))
    index = _section_index(parsed, name)
    sections = list(parsed.sections)
    del sections[index]
    return parse(parsed.preamble + "".join(section.raw for section in sections))


def rename_section(parsed: ParsedBody, old_name: str, new_name: str) -> ParsedBody:
    if old_name == _PREAMBLE or new_name == _PREAMBLE:
        raise InvalidPosition("_preamble cannot be renamed")
    index = _section_index(parsed, old_name)
    if any(section.name == new_name for section in parsed.sections):
        raise SectionExists(new_name)
    sections = list(parsed.sections)
    ending = "\r\n" if sections[index].heading.endswith("\r\n") else "\n" if sections[index].heading.endswith("\n") else ""
    sections[index] = replace(sections[index], name=new_name, heading=f"## {new_name}{ending}")
    return parse(parsed.preamble + "".join(section.raw for section in sections))


def reorder(parsed: ParsedBody, names: list[str]) -> ParsedBody:
    current = [section.name for section in parsed.sections]
    if sorted(names) != sorted(current) or len(names) != len(current):
        missing = next((name for name in current if name not in names), None)
        raise SectionNotFound(missing or "section")
    by_name = {section.name: section for section in parsed.sections}
    return parse(parsed.preamble + "".join(by_name[name].raw for name in names))


